import torch.nn.functional as F


class CausalConv1d(nn.Module):
    """
    1D causal convolution: output at position t depends only on positions <= t.
    Implemented as left-padding rather than weight masking.
    """
    def __init__(self, in_ch: int, out_ch: int, kernel_size: int, dilation: int = 1):
        super().__init__()
        self.pad = (kernel_size - 1) * dilation  # left-only padding
        self.conv = nn.Conv1d(in_ch, out_ch, kernel_size, dilation=dilation)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # x: [B, C, T]
        x_padded = F.pad(x, (self.pad, 0))   # pad T on the left only
        return self.conv(x_padded)


# WaveNet-style dilated causal conv stack
class DilatedCausalStack(nn.Module):
    def __init__(self, ch: int, n_layers: int = 8, max_dilation: int = 8):
        super().__init__()
        self.layers = nn.ModuleList([
            CausalConv1d(ch, ch, kernel_size=2, dilation=2 ** (i % max_dilation))
            for i in range(n_layers)
        ])

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        for layer in self.layers:
            x = x + torch.tanh(layer(x))  # residual + gated act (simplified)
        return x
